import { d3_map, d3_set } from '../../core/d3-constants';
import { bubbleSelection } from '../../scatter/bubbleSelection';
import { chartcategory } from '../../core/main-zc-init';
import { barSelection } from '../../bar/bar-selection';
import { ScatterSelection } from '../../scatter/scatterSelection';
import { areaSelection } from '../../area/areaSelection';
import { bubblePieSelection } from '../../bubblepie/bubblepie-selection';
import {
    POLY_TYPES,
    BISECT_TYPES,
    BISECT_NORM_TYPES,
    BISECT_LEVEL_TYPES,
    BISECT_SEGMENT_TYPES,
    QUADTREE_NORM_TYPES,
    QUADTREE_SIZE_TYPES,
    QUADTREE_PIE_TYPES,
    QUADTREE_BOUND_TYPES,
    QUADTREE_TEXT_TYPES,
    SEGMENT_TYPES,
    PATH_TYPES
} from './search-mode';

import { boxplotSelection, barWithSegmentSelection } from '../../boxplot/boxplot-selection';
import { segmentSelection } from '../../scatter/segment-selection';
import { TreemapSelection } from '../../treemap/treemap-selection';
import { WordCloudSelection } from '../../wordcloud/wordcloud-selection';

export var SELECTION_TOOL = d3_map();
var availableModes = [
    POLY_TYPES,
    PATH_TYPES,
    BISECT_NORM_TYPES,
    BISECT_LEVEL_TYPES,
    BISECT_SEGMENT_TYPES,
    QUADTREE_NORM_TYPES,
    QUADTREE_SIZE_TYPES,
    QUADTREE_PIE_TYPES,
    QUADTREE_BOUND_TYPES,
    QUADTREE_TEXT_TYPES,
    SEGMENT_TYPES
];
var matchers = [
    'POLY_TYPES',
    'PATH_TYPES',
    'BISECT_NORM_TYPES',
    'BISECT_LEVEL_TYPES',
    'BISECT_SEGMENT_TYPES',
    'QUADTREE_NORM_TYPES',
    'QUADTREE_SIZE_TYPES',
    'QUADTREE_PIE_TYPES',
    'QUADTREE_BOUND_TYPES',
    'QUADTREE_TEXT_TYPES',
    'SEGMENT_TYPES'
];

SELECTION_TOOL.set('POLY_TYPES', areaSelection);
SELECTION_TOOL.set('PATH_TYPES', areaSelection);
SELECTION_TOOL.set('BISECT_NORM_TYPES', barSelection);
SELECTION_TOOL.set('BISECT_LEVEL_TYPES', boxplotSelection);
SELECTION_TOOL.set('BISECT_SEGMENT_TYPES', barWithSegmentSelection);
SELECTION_TOOL.set('QUADTREE_NORM_TYPES', ScatterSelection);
SELECTION_TOOL.set('QUADTREE_SIZE_TYPES', bubbleSelection);
SELECTION_TOOL.set('QUADTREE_PIE_TYPES', bubblePieSelection);
SELECTION_TOOL.set('QUADTREE_BOUND_TYPES', TreemapSelection);
SELECTION_TOOL.set('QUADTREE_TEXT_TYPES', WordCloudSelection);
SELECTION_TOOL.set('QUADTREE_TYPES', bubblePieSelection);
SELECTION_TOOL.set('SEGMENT_TYPES', segmentSelection);

export function getSelectionTool(type) {
    var tool;
    availableModes.some((d, i) => {
        if (d.has(type)) {
            tool = SELECTION_TOOL.get(matchers[i]);
            return true;
        }
    });
    return tool;
}
